1	import type { StatuslineConfig } from "./config-types";
2	
3	export interface MenuOption {
4		path: string;
5		label: string;
6		type: "boolean" | "cycle" | "section";
7		getValue?: (config: StatuslineConfig) => boolean | string;
8		toggle?: (config: StatuslineConfig) => void;
9		cycle?: (config: StatuslineConfig, direction: 1 | -1) => void;
10		choices?: string[];
11		indent?: number;
12		hidden?: (config: StatuslineConfig) => boolean;
13	}
14	
15	type ConfigPath = string;
16	type GetValue<T> = (config: StatuslineConfig) => T;
17	type SetValue<T> = (config: StatuslineConfig, value: T) => void;
18	
19	function getNestedValue(obj: unknown, path: string): unknown {
20		return path.split(".").reduce((current, key) => {
21			if (current && typeof current === "object" && key in current) {
22				return (current as Record<string, unknown>)[key];
23			}
24			return undefined;
25		}, obj);
26	}
27	
28	function setNestedValue(obj: unknown, path: string, value: unknown): void {
29		const keys = path.split(".");
30		const lastKey = keys.pop();
31		if (!lastKey) return;
32	
33		let current = obj;
34		for (const key of keys) {
35			if (current && typeof current === "object" && key in current) {
36				current = (current as Record<string, unknown>)[key];
37			} else {
38				return;
39			}
40		}
41	
42		if (current && typeof current === "object") {
43			(current as Record<string, unknown>)[lastKey] = value;
44		}
45	}
46	
47	export function section(
48		path: string,
49		label: string,
50		options?: {
51			enabledPath?: string;
52		},
53	): MenuOption {
54		if (options?.enabledPath) {
55			return {
56				path,
57				label,
58				type: "section",
59				getValue: (c) => getNestedValue(c, options.enabledPath!) as boolean,
60				toggle: (c) => {
61					const current = getNestedValue(c, options.enabledPath!) as boolean;
62					setNestedValue(c, options.enabledPath!, !current);
63				},
64			};
65		}
66		return { path, label, type: "section" };
67	}
68	
69	export function toggle(
70		path: string,
71		label: string,
72		options?: {
73			indent?: number;
74			hidden?: (config: StatuslineConfig) => boolean;
75		},
76	): MenuOption {
77		return {
78			path,
79			label,
80			type: "boolean",
81			getValue: (c) => getNestedValue(c, path) as boolean,
82			toggle: (c) => {
83				const current = getNestedValue(c, path) as boolean;
84				setNestedValue(c, path, !current);
85			},
86			indent: options?.indent ?? 1,
87			hidden: options?.hidden,
88		};
89	}
90	
91	export function cycle<T extends string | number>(
92		path: string,
93		label: string,
94		choices: readonly T[],
95		options?: {
96			indent?: number;
97			hidden?: (config: StatuslineConfig) => boolean;
98			displayValue?: (value: T) => string;
99		},
100	): MenuOption {
101		const stringChoices = choices.map((c) =>
102			options?.displayValue ? options.displayValue(c) : String(c),
103		);
104	
105		return {
106			path,
107			label,
108			type: "cycle",
109			choices: stringChoices,
110			getValue: (c) => {
111				const value = getNestedValue(c, path) as T;
112				return options?.displayValue
113					? options.displayValue(value)
114					: String(value);
115			},
116			cycle: (c, dir) => {
117				const current = getNestedValue(c, path) as T;
118				const currentIndex = choices.indexOf(current);
119				const next = (currentIndex + dir + choices.length) % choices.length;
120				setNestedValue(c, path, choices[next]);
121			},
122			indent: options?.indent ?? 1,
123			hidden: options?.hidden,
124		};
125	}
126	
127	export function progressBarOptions(
128		basePath: string,
129		parentHidden: (config: StatuslineConfig) => boolean,
130	): MenuOption[] {
131		const barPath = `${basePath}.progressBar`;
132	
133		return [
134			toggle(`${barPath}.enabled`, "Progress bar", {
135				indent: 2,
136				hidden: parentHidden,
137			}),
138			cycle(`${barPath}.style`, "Style", PROGRESS_BAR_STYLES, {
139				indent: 3,
140				hidden: (c) =>
141					parentHidden(c) ||
142					!(getNestedValue(c, `${barPath}.enabled`) as boolean),
143			}),
144			cycle(`${barPath}.length`, "Length", PROGRESS_BAR_LENGTHS, {
145				indent: 3,
146				hidden: (c) =>
147					parentHidden(c) ||
148					!(getNestedValue(c, `${barPath}.enabled`) as boolean),
149			}),
150			cycle(`${barPath}.color`, "Color", PROGRESS_BAR_COLORS, {
151				indent: 3,
152				hidden: (c) =>
153					parentHidden(c) ||
154					!(getNestedValue(c, `${barPath}.enabled`) as boolean),
155			}),
156			cycle(`${barPath}.background`, "Background", PROGRESS_BAR_BACKGROUNDS, {
157				indent: 3,
158				hidden: (c) =>
159					parentHidden(c) ||
160					!(getNestedValue(c, `${barPath}.enabled`) as boolean),
161			}),
162		];
163	}
164	
165	export function percentageOptions(
166		basePath: string,
167		parentHidden: (config: StatuslineConfig) => boolean,
168	): MenuOption[] {
169		const pctPath = basePath;
170	
171		return [
172			toggle(`${pctPath}.enabled`, "Percentage display", {
173				indent: 1,
174				hidden: parentHidden,
175			}),
176			toggle(`${pctPath}.showValue`, "Show percentage value", {
177				indent: 2,
178				hidden: (c) =>
179					parentHidden(c) ||
180					!(getNestedValue(c, `${pctPath}.enabled`) as boolean),
181			}),
182			...progressBarOptions(
183				pctPath,
184				(c) =>
185					parentHidden(c) ||
186					!(getNestedValue(c, `${pctPath}.enabled`) as boolean),
187			),
188		];
189	}
190	
191	export const SEPARATORS = [
192		"|",
193		"•",
194		"·",
195		"⋅",
196		"●",
197		"◆",
198		"▪",
199		"▸",
200		"›",
201		"→",
202	] as const;
203	export const PATH_DISPLAY_MODES = ["truncated", "basename", "full"] as const;
204	export const PROGRESS_BAR_STYLES = ["filled", "rectangle", "braille"] as const;
205	export const PROGRESS_BAR_LENGTHS = [5, 10, 15] as const;
206	export const PROGRESS_BAR_COLORS = [
207		"progressive",
208		"green",
209		"yellow",
210		"red",
211		"peach",
212		"black",
213		"white",
214	] as const;
215	export const PROGRESS_BAR_BACKGROUNDS = [
216		"none",
217		"dark",
218		"gray",
219		"light",
220		"blue",
221		"purple",
